FILE_CATEGORIES = {
    "images": [".jpg", ".jpeg", ".png", ".gif", ".bmp", ".svg", ".webp"],
    "documents": [".pdf", ".doc", ".docx", ".txt", ".odt", ".rtf", ".xls", ".xlsx", ".ppt", ".pptx"],
    "videos": [".mp4", ".avi", ".mov", ".mkv", ".flv", ".wmv", ".m4v"],
    "archives": [".zip", ".tar", ".gz", ".rar", ".7z", ".bz2", ".xz"],
    "audio": [".mp3", ".wav", ".flac", ".aac", ".ogg", ".wma"],
    "code": [".py", ".js", ".ts", ".java", ".c", ".cpp", ".h", ".cs", ".rb", ".go", ".rs"],
    "data": [".csv", ".json", ".xml", ".sql", ".db"],
    "executables": [".exe", ".dmg", ".pkg", ".app", ".bin"],
}

def get_category(file_extension):
    ext = file_extension.lower()
    for category, extensions in FILE_CATEGORIES.items():
        if ext in extensions:
            return category
    return None

def get_all_extensions():
    all_exts = []
    for extensions in FILE_CATEGORIES.values():
        all_exts.extend(extensions)
    return all_exts

import os
from pathlib import Path

def scan_directory(directory):
    dir_path = Path(directory)
    if not dir_path.exists():
        raise ValueError(f"Directory does not exist: {directory}")
    if not dir_path.is_dir():
        raise ValueError(f"Path is not a directory: {directory}")

    files = []
    for item in dir_path.iterdir():
        if item.is_file():
            files.append(item)
    return files

def create_category_folders(directory, categories):
    dir_path = Path(directory)
    created_folders = []
    for category in categories:
        folder_path = dir_path / category
        if not folder_path.exists():
            folder_path.mkdir(parents=True, exist_ok=True)
            created_folders.append(category)
    return created_folders

def move_file(file_path, destination_folder, dry_run=False):
    source = Path(file_path)
    destination = destination_folder / source.name

    if dry_run:
        return str(source), str(destination)

    destination.mkdir(parents=True, exist_ok=True)
    destination.parent.mkdir(parents=True, exist_ok=True)

    if destination.exists():
        base_name = source.stem
        suffix = source.suffix
        counter = 1
        while destination.exists():
            new_name = f"{base_name}_{counter}{suffix}"
            destination = destination.parent / new_name
            counter += 1

    source.replace(destination)
    return str(source), str(destination)

def format_file_size(file_path):
    size = file_path.stat().st_size
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size < 1024:
            return f"{size:.2f} {unit}"
        size /= 1024
    return f"{size:.2f} PB"

from pathlib import Path
from file_types import get_category
from utils import scan_directory, create_category_folders, move_file

class FileOrganizer:
    def __init__(self, directory, dry_run=False):
        self.directory = Path(directory)
        self.dry_run = dry_run
        self.moved_files = []
        self.created_folders = []
        self.unrecognized_files = []

    def organize(self):
        files = scan_directory(self.directory)

        if not files:
            print(f"No files found in {self.directory}")
            return

        category_folders = set()
        for file_path in files:
            extension = file_path.suffix
            category = get_category(extension)
            if category:
                category_folders.add(category)

        self.created_folders = create_category_folders(self.directory, category_folders)

        for file_path in files:
            extension = file_path.suffix
            category = get_category(extension)

            if category:
                category_folder = self.directory / category
                source, dest = move_file(file_path, category_folder, self.dry_run)
                self.moved_files.append((source, dest))
            else:
                self.unrecognized_files.append(str(file_path))

        self._print_report()

    def _print_report(self):
        print(f"\n{'='*60}")
        print(f"Organization Report - {self.directory}")
        print(f"{'='*60}\n")

        if self.created_folders:
            print(f"Created {len(self.created_folders)} folder(s):")
            for folder in self.created_folders:
                print(f"  - {folder}/")
            print()

        if self.moved_files:
            print(f"Moved {len(self.moved_files)} file(s):")
            for source, dest in self.moved_files:
                print(f"  {source.name} -> {Path(dest).parent.name}/")
            print()

        if self.unrecognized_files:
            print(f"Unrecognized files ({len(self.unrecognized_files)}):")
            for f in self.unrecognized_files:
                print(f"  - {Path(f).name}")
            print()

        if self.dry_run:
            print("DRY RUN - No files were actually moved.")

        print(f"{'='*60}\n")

